USE QLSVNhom;
GO

DELETE FROM dbo.BANGDIEM WHERE MASV IN ('SV01','SV02','SV03');
DELETE FROM dbo.SINHVIEN WHERE MASV IN ('SV01','SV02','SV03');
DELETE FROM dbo.HOCPHAN WHERE MAHP IN ('HP01','HP02','HP03');
DELETE FROM dbo.LOP WHERE MALOP IN ('L01','L02','L03');
DELETE FROM dbo.NHANVIEN WHERE MANV IN ('NV11','NV12','NV13');
GO

/* NHANVIEN: insert qua stored procedure với dữ liệu đã hash / encrypt ở client */
/* Plain passwords used for these hashes:
   NV11 / nvan  / DbSec@P@ss01
   NV12 / tbinh / DbSec@P@ss02
   NV13 / lqhuy / DbSec@P@ss03
*/

/*
    Paste output từ sec.py xuống 3 cái EXEC NV ở dưới ------------------------------------------------------------------
*/

EXEC dbo.SP_INS_PUBLIC_ENCRYPT_NHANVIEN
    'NV11',
    N'Nguyen Van An',
    'nv11@fit.vn',
    '',
    N'nvan',
    '7EAA38E23AD215EE9A515499B01F6F60DE65D3C8BA5E79E039B6EE07633BA0B46F334784DA8D79E37C70F745558A4F820346C426C8EEDEA0390445413688AB99',
    '';

EXEC dbo.SP_INS_PUBLIC_ENCRYPT_NHANVIEN
    'NV12',
    N'Tran Thi Binh',
    'nv12@fit.vn',
    '',
    N'tbinh',
    '33C124659B36921C477552EE046E7E88F81F694653906A955E703B332C4E7B7FC587AFF3E4FC332B5A2E14651A0CAB2DC01658F26F1AB59AF80BA3CC34B05B37',
    '';

EXEC dbo.SP_INS_PUBLIC_ENCRYPT_NHANVIEN
    'NV13',
    N'Le Quang Huy',
    'nv13@fit.vn',
    '',
    N'lqhuy',
    'D8120293A537E9F0BD4DC8A97DC3625C6D6682D5ACBA7EA8964D963AE1A27AA5F65BDB847417960ECCA2F56BF14A2DCE1CB5193B2627F98136A8ECB08FB684B0',
    '';
GO

